package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.HashSet;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.Set;

import org.eclipse.rdf4j.common.annotation.Experimental;
import org.eclipse.rdf4j.query.algebra.Difference;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.LeftJoin;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.UnaryTupleOperator;

/**
 * Task-style top-down Cascades search over memo groups.
 */
@Experimental
public final class CascadesPlanner {
	private static final int DEFAULT_FRONTIER_LIMIT = 16;

	private final CascadesCostModel costModel;
	private final RuleRegistry ruleRegistry;
	private final CascadesTelemetry telemetry;
	private final int boundedFrontierLimit;

	public CascadesPlanner(CascadesCostModel costModel, RuleRegistry ruleRegistry, CascadesTelemetry telemetry) {
		this(costModel, ruleRegistry, telemetry, DEFAULT_FRONTIER_LIMIT);
	}

	public CascadesPlanner(CascadesCostModel costModel, RuleRegistry ruleRegistry, CascadesTelemetry telemetry,
			int boundedFrontierLimit) {
		this.costModel = costModel;
		this.ruleRegistry = ruleRegistry == null ? RuleRegistry.standardLogicalRules() : ruleRegistry;
		this.telemetry = telemetry == null ? CascadesTelemetry.NO_OP : telemetry;
		this.boundedFrontierLimit = Math.max(1, boundedFrontierLimit);
	}

	public CascadesPlan optimize(TupleExpr root, OptimizationGoal goal) {
		OptimizationGoal normalizedGoal = goal == null ? OptimizationGoal.root() : goal;
		Memo memo = new Memo(costModel);
		int rootGroup = memo.intern(root);
		SearchState state = new SearchState(normalizedGoal.taskBudget(), normalizedGoal.searchMode());
		Winner winner = optimizeGroup(memo, rootGroup, normalizedGoal, state).orElse(null);
		if (winner != null) {
			winner = state.withCurrentRejections(winner, normalizedGoal);
		}
		boolean approximate = state.approximate || (winner != null && winner.approximate());
		List<String> diagnostics = state.diagnostics();
		if (winner != null) {
			telemetry.winnerChosen(normalizedGoal.key(rootGroup), winner);
		}
		return new CascadesPlan(memo, rootGroup, normalizedGoal, Optional.ofNullable(winner), approximate, diagnostics);
	}

	private Optional<Winner> optimizeGroup(Memo memo, int groupId, OptimizationGoal goal, SearchState state) {
		if (!state.consume("optimizeGroup:" + groupId) || goal.expired()) {
			state.markApproximate("budget-or-timeout optimizing group " + groupId);
			return memo.bestWinner(goal.key(groupId));
		}
		WinnerKey key = goal.key(groupId);
		Optional<Winner> cached = memo.bestWinner(key);
		if (cached.isPresent()) {
			return cached;
		}
		if (memo.hasFailure(key)) {
			return Optional.empty();
		}
		exploreGroup(memo, groupId, goal, state);
		MemoGroup group = memo.group(groupId);
		List<MemoExpr> snapshot = List.copyOf(group.mutableExpressionsView());
		for (MemoExpr expression : snapshot) {
			optimizeExpression(memo, expression, goal, state);
		}
		Optional<Winner> best = memo.bestWinner(key);
		if (best.isEmpty()) {
			memo.recordFailure(key);
		}
		best.ifPresent(winner -> telemetry.winnerChosen(key, winner));
		return best;
	}

	private void exploreGroup(Memo memo, int groupId, OptimizationGoal goal, SearchState state) {
		if (!state.consume("exploreGroup:" + groupId)) {
			state.markApproximate("budget while exploring group " + groupId);
			return;
		}
		RuleContext context = new RuleContext(memo, costModel, telemetry, state);
		MemoGroup group = memo.group(groupId);
		int index = 0;
		while (index < group.mutableExpressionsView().size()) {
			if (goal.expired()) {
				state.markApproximate("timeout while exploring group " + groupId);
				return;
			}
			MemoExpr expression = group.mutableExpressionsView().get(index++);
			for (CascadesRule rule : ruleRegistry.applicableRules(expression, goal, memo)) {
				boolean addedOpaqueAlternative = applyRule(memo, expression, rule, goal, context, state);
				if (addedOpaqueAlternative
						&& goal.searchMode() == OptimizationGoal.SearchMode.BUDGETED
						&& rule.kind() == RuleKind.IMPLEMENTATION) {
					return;
				}
				if (state.approximate && goal.searchMode() == OptimizationGoal.SearchMode.BUDGETED) {
					return;
				}
			}
		}
	}

	private boolean applyRule(Memo memo, MemoExpr expression, CascadesRule rule, OptimizationGoal goal,
			RuleContext context, SearchState state) {
		String firedKey = expression.id() + ":" + rule.id() + ":" + goal.requiredProperties() + ":"
				+ goal.semanticScope() + ":" + goal.costPolicy();
		if (!state.ruleFired.add(firedKey)) {
			return false;
		}
		if (!state.consume("applyRule:" + rule.id())) {
			state.markApproximate("budget applying rule " + rule.id());
			return false;
		}
		List<RuleApplication> applications = rule.apply(expression, goal, context);
		if (applications == null || applications.isEmpty()) {
			state.recordPatternExploration(expression.structuralKey());
			return false;
		}
		boolean addedOpaqueAlternative = false;
		for (RuleApplication application : applications) {
			RuleProof ruleProof = application.proofs().isEmpty() ? rule.proof(expression, goal, context)
					: application.proofs().getFirst();
			telemetry.alternativeConsidered(application.targetGroupId(), rule.id(), application.kind(),
					application.deliveredProperties(), application.localCost(), application.metadata(),
					application.alternative());
			telemetry.ruleFired(expression.groupId(), rule.id(), ruleProof);
			if (application.kind() == RuleKind.TRANSFORMATION) {
				memo.addLogicalAlternative(application.targetGroupId(), application.alternative());
			} else {
				memo.addPhysicalAlternative(application.targetGroupId(), application.alternative(),
						application.deliveredProperties(), application.metadata(), application.kind(),
						application.localCost(),
						application.proofs(), application.estimate(), application.opaque());
				addedOpaqueAlternative |= application.opaque();
			}
		}
		return addedOpaqueAlternative;
	}

	private Optional<Winner> optimizeExpression(Memo memo, MemoExpr expression, OptimizationGoal goal,
			SearchState state) {
		if (!state.consume("optimizeExpression:" + expression.id()) || goal.expired()) {
			state.markApproximate("budget-or-timeout optimizing expression " + expression.id());
			return Optional.empty();
		}
		if (!expression.physical()) {
			return Optional.empty();
		}
		String ruleId = primaryRuleId(expression);
		List<Winner> inputWinners = optimizeInputs(memo, expression, goal, state);
		if (inputWinners.size() != expression.inputGroupIds().size()) {
			state.recordRejected(expression.groupId(), ruleId, "missing-input-winner", CostVector.INFINITE);
			telemetry.alternativeDiscarded(expression.groupId(), ruleId, "missing-input-winner",
					CostVector.INFINITE, expression.tupleExpr());
			return Optional.empty();
		}
		PhysicalProperties delivered = costModel.deliveredProperties(expression, goal, inputWinners);
		if (!delivered.satisfies(goal.requiredProperties())) {
			state.recordRejected(expression.groupId(), ruleId, "missing-physical-property", CostVector.ZERO,
					goal.requiredProperties(), delivered);
			telemetry.alternativeDiscarded(expression.groupId(), ruleId, "missing-physical-property",
					CostVector.ZERO, expression.tupleExpr());
			return Optional.empty();
		}
		if (goal.excludes(delivered)) {
			state.recordRejected(expression.groupId(), ruleId, "excluded-physical-property", CostVector.ZERO,
					goal.requiredProperties(), delivered);
			telemetry.alternativeDiscarded(expression.groupId(), ruleId, "excluded-physical-property",
					CostVector.ZERO, expression.tupleExpr());
			return Optional.empty();
		}
		CostVector cost = costModel.localCost(expression, goal, inputWinners).plus(expression.ruleCost());
		telemetry.alternativeCosted(expression.groupId(), ruleId, goal.requiredProperties(), delivered, cost,
				expression.tupleExpr());
		if (goal.searchMode() == OptimizationGoal.SearchMode.BUDGETED && cost.exceeds(goal.costBound())) {
			state.recordRejected(expression.groupId(), ruleId, "cost-bound", cost);
			telemetry.alternativeDiscarded(expression.groupId(), ruleId, "cost-bound", cost, expression.tupleExpr());
			return Optional.empty();
		}
		TupleExpr plan = costModel.buildPlan(expression, inputWinners);
		List<RuleProof> proofs = new ArrayList<>(expression.proofs());
		for (Winner inputWinner : inputWinners) {
			proofs.addAll(inputWinner.proofs());
		}
		ruleId = primaryRuleId(expression, proofs);
		RuleKind ruleKind = primaryRuleKind(expression, proofs);
		List<PlanProvenance> inputProvenance = inputWinners.stream()
				.map(Winner::provenance)
				.toList();
		PlanProvenance provenance = new PlanProvenance(expression.groupId(), expression.id(), expression.operator(),
				ruleId, ruleKind, inputProvenance, expression.estimate(), cost, goal.requiredProperties(), delivered,
				state.rejectionsFor(expression.groupId()), proofs, state.approximate, state.approximateReason);
		Winner winner = new Winner(expression, plan, delivered, cost, proofs, state.approximate,
				state.approximateReason, provenance);
		WinnerKey winnerKey = goal.key(expression.groupId());
		if (goal.searchMode() == OptimizationGoal.SearchMode.BUDGETED
				&& memo.winners(winnerKey).size() >= boundedFrontierLimit) {
			state.markApproximate("bounded winner frontier reached for group " + expression.groupId());
		}
		boolean accepted = memo.addWinner(winnerKey, winner, boundedFrontierLimit,
				goal.searchMode() != OptimizationGoal.SearchMode.BUDGETED);
		if (!accepted) {
			state.recordRejected(expression.groupId(), ruleId, "dominated-or-trimmed", cost);
			telemetry.alternativeDiscarded(expression.groupId(), ruleId, "dominated-or-trimmed", cost, plan);
		} else {
			telemetry.alternativeAccepted(expression.groupId(), ruleId, cost, plan);
		}
		return accepted ? Optional.of(winner) : Optional.empty();
	}

	private List<Winner> optimizeInputs(Memo memo, MemoExpr expression, OptimizationGoal goal, SearchState state) {
		if (expression.inputGroupIds().isEmpty()) {
			return List.of();
		}
		List<Winner> winners = new ArrayList<>(expression.inputGroupIds().size());
		List<OptimizationGoal> inputGoals = inputGoals(expression, goal);
		for (int i = 0; i < expression.inputGroupIds().size(); i++) {
			Integer inputGroupId = expression.inputGroupIds().get(i);
			OptimizationGoal inputGoal = inputGoals.get(i);
			Optional<Winner> inputWinner = optimizeGroup(memo, inputGroupId, inputGoal, state);
			if (inputWinner.isEmpty()) {
				return List.of();
			}
			winners.add(inputWinner.get());
		}
		return winners;
	}

	private List<OptimizationGoal> inputGoals(MemoExpr expression, OptimizationGoal goal) {
		int inputCount = expression.inputGroupIds().size();
		TupleExpr tupleExpr = expression.tupleExpr();
		if (inputCount == 1 && tupleExpr instanceof UnaryTupleOperator unary) {
			return List.of(inputGoal(goal, unary.getArg(), Set.of()));
		}
		if (inputCount == 2 && tupleExpr instanceof LeftJoin leftJoin) {
			return List.of(inputGoal(goal, leftJoin.getLeftArg(), Set.of()),
					inputGoal(goal, leftJoin.getRightArg(), leftJoin.getLeftArg().getAssuredBindingNames()));
		}
		if (inputCount == 2 && tupleExpr instanceof Join join) {
			return List.of(inputGoal(goal, join.getLeftArg(), Set.of()),
					inputGoal(goal, join.getRightArg(), join.getLeftArg().getAssuredBindingNames()));
		}
		if (inputCount == 2 && tupleExpr instanceof Difference difference) {
			return List.of(inputGoal(goal, difference.getLeftArg(), Set.of()),
					inputGoal(goal, difference.getRightArg(), difference.getLeftArg().getAssuredBindingNames()));
		}
		List<OptimizationGoal> goals = new ArrayList<>(inputCount);
		for (int i = 0; i < inputCount; i++) {
			goals.add(goal.withRequiredProperties(PhysicalProperties.ANY));
		}
		return goals;
	}

	private OptimizationGoal inputGoal(OptimizationGoal goal, TupleExpr input, Set<String> contextualBoundVars) {
		Set<String> boundVars = childBoundVars(goal, input, contextualBoundVars);
		PhysicalProperties required = boundVars.isEmpty()
				? PhysicalProperties.ANY
				: PhysicalProperties.builder().boundVars(boundVars).build();
		return goal.withRequiredProperties(required);
	}

	private Set<String> childBoundVars(OptimizationGoal goal, TupleExpr input, Set<String> contextualBoundVars) {
		if (input == null) {
			return Set.of();
		}
		Set<String> inputBindings = input.getBindingNames();
		if (inputBindings.isEmpty()) {
			return Set.of();
		}
		Set<String> boundVars = new LinkedHashSet<>();
		if (goal != null) {
			for (String boundVar : goal.requiredProperties().boundVars()) {
				if (inputBindings.contains(boundVar)) {
					boundVars.add(boundVar);
				}
			}
		}
		if (contextualBoundVars != null) {
			for (String contextualBoundVar : contextualBoundVars) {
				if (inputBindings.contains(contextualBoundVar)) {
					boundVars.add(contextualBoundVar);
				}
			}
		}
		return boundVars.isEmpty() ? Set.of() : Set.copyOf(boundVars);
	}

	private static String primaryRuleId(MemoExpr expression) {
		return primaryRuleId(expression, expression.proofs());
	}

	private static String primaryRuleId(MemoExpr expression, List<RuleProof> proofs) {
		if (proofs != null && !proofs.isEmpty()) {
			return proofs.getFirst().ruleId();
		}
		return expression == null ? "unknown" : expression.operator();
	}

	private static RuleKind primaryRuleKind(MemoExpr expression, List<RuleProof> proofs) {
		if (proofs != null && !proofs.isEmpty()) {
			return proofs.getFirst().kind();
		}
		return expression == null ? RuleKind.IMPLEMENTATION : expression.kind();
	}

	public static final class SearchState {
		private int remainingBudget;
		private final OptimizationGoal.SearchMode mode;
		private boolean approximate;
		private String approximateReason = "";
		private final Set<String> ruleFired = new HashSet<>();
		private final Set<String> patternExplorationMemory = new HashSet<>();
		private final Map<String, Integer> taskCounts = new HashMap<>();
		private final Map<Integer, List<RejectedAlternative>> rejectedAlternativesByGroup = new HashMap<>();

		SearchState(int budget, OptimizationGoal.SearchMode mode) {
			this.remainingBudget = budget <= 0 ? Integer.MAX_VALUE : budget;
			this.mode = mode == null ? OptimizationGoal.SearchMode.EXACT : mode;
		}

		boolean consume(String taskName) {
			taskCounts.merge(taskName, 1, Integer::sum);
			if (remainingBudget == Integer.MAX_VALUE) {
				return true;
			}
			remainingBudget--;
			if (remainingBudget >= 0) {
				return true;
			}
			if (mode == OptimizationGoal.SearchMode.BUDGETED) {
				markApproximate("task budget exhausted at " + taskName);
			}
			return mode != OptimizationGoal.SearchMode.BUDGETED;
		}

		void markApproximate(String reason) {
			approximate = true;
			if (approximateReason.isBlank()) {
				approximateReason = reason == null ? "approximate" : reason;
			}
		}

		void recordPatternExploration(String key) {
			if (key != null) {
				patternExplorationMemory.add(key);
			}
		}

		void recordRejected(int groupId, String ruleId, String reason, CostVector cost) {
			rejectedAlternativesByGroup.computeIfAbsent(groupId, ignored -> new ArrayList<>())
					.add(new RejectedAlternative(groupId, ruleId, reason, cost));
		}

		void recordRejected(int groupId, String ruleId, String reason, CostVector cost,
				PhysicalProperties requiredProperties, PhysicalProperties deliveredProperties) {
			rejectedAlternativesByGroup.computeIfAbsent(groupId, ignored -> new ArrayList<>())
					.add(new RejectedAlternative(groupId, ruleId, reason, cost, requiredProperties,
							deliveredProperties, List.of()));
		}

		List<RejectedAlternative> rejectionsFor(int groupId) {
			List<RejectedAlternative> rejectedAlternatives = rejectedAlternativesByGroup.get(groupId);
			return rejectedAlternatives == null || rejectedAlternatives.isEmpty() ? List.of()
					: List.copyOf(rejectedAlternatives);
		}

		Winner withCurrentRejections(Winner winner, OptimizationGoal goal) {
			if (winner == null) {
				return null;
			}
			PlanProvenance provenance = winner.provenance()
					.withRejectedAlternatives(rejectionsFor(winner.expression().groupId()))
					.withApproximation(approximate || winner.approximate(),
							approximateReason.isBlank() ? winner.reason() : approximateReason);
			return winner.withProvenance(provenance);
		}

		List<String> diagnostics() {
			List<String> diagnostics = new ArrayList<>();
			diagnostics.add("tasks=" + taskCounts);
			diagnostics.add("ruleFired=" + ruleFired.size());
			diagnostics.add("patternsExplored=" + patternExplorationMemory.size());
			if (approximate) {
				diagnostics.add("approximate=" + approximateReason);
			}
			return List.copyOf(diagnostics);
		}
	}
}
